import { parseConfig } from './src/parser.js';
import assert from 'node:assert/strict';

// Basic key-value
const basic = parseConfig('name = Alice\nage = 30\nactive = true');
assert.equal(basic.default.name, 'Alice');
assert.equal(basic.default.age, 30);
assert.equal(basic.default.active, true);

// Sections
const sectioned = parseConfig(`
[database]
host = localhost
port = 5432

[app]
debug = false
name = MyApp
`);
assert.equal(sectioned.database.host, 'localhost');
assert.equal(sectioned.database.port, 5432);
assert.equal(sectioned.app.debug, false);
assert.equal(sectioned.app.name, 'MyApp');

// Comments and blank lines
const commented = parseConfig(`
# This is a comment
key1 = value1

# Another comment
key2 = value2
`);
assert.equal(commented.default.key1, 'value1');
assert.equal(commented.default.key2, 'value2');
assert.equal(Object.keys(commented.default).length, 2);

// Multiline quoted values
const multiline = parseConfig(`
[server]
description = "This is a
multiline
value"
port = 8080
`);
assert.equal(multiline.server.description, 'This is a\nmultiline\nvalue');
assert.equal(multiline.server.port, 8080);

// Mixed default and sections
const mixed = parseConfig(`
global_key = global_value

[section1]
key = val1

[section2]
key = val2
`);
assert.equal(mixed.default.global_key, 'global_value');
assert.equal(mixed.section1.key, 'val1');
assert.equal(mixed.section2.key, 'val2');

// Edge cases
const edges = parseConfig(`
spaced   =   lots of spaces   
noquote = simple value
num_zero = 0
falsy = false
empty_section_before_content = yes
[empty]
[nonempty]
key = val
`);
assert.equal(edges.default.spaced, 'lots of spaces');
assert.equal(edges.default.num_zero, 0);
assert.equal(edges.default.falsy, false);
assert.ok('empty' in edges, 'Empty section should exist');
assert.equal(edges.nonempty.key, 'val');

// Empty input
const empty = parseConfig('');
assert.deepEqual(empty, { default: {} });

console.log('All tests passed');
